import { useState, useEffect } from 'react'
import { X, Bookmark, BookmarkCheck, Check, Tag, Clock, User, MessageSquare } from 'lucide-react'
import { motion } from 'framer-motion'
import { PriorityBadge, TypeBadge } from '../ui/Badges'
import Button from '../ui/Button'
import { evidenceApi } from '../../services/api'
import { useToast } from '../ui/Toast'

function EvidenceDetail({ caseId, evidenceId, onClose, onUpdate }) {
    const [evidence, setEvidence] = useState(null)
    const [loading, setLoading] = useState(true)
    const [notes, setNotes] = useState('')
    const [newTag, setNewTag] = useState('')
    const [saving, setSaving] = useState(false)
    const toast = useToast()

    useEffect(() => {
        if (evidenceId) {
            loadEvidence()
        }
    }, [evidenceId])

    const loadEvidence = async () => {
        setLoading(true)
        try {
            const result = await evidenceApi.get(caseId, evidenceId)
            setEvidence(result.data)
            setNotes(result.data.notes || '')
        } catch (error) {
            toast.error('Failed to load evidence details')
        } finally {
            setLoading(false)
        }
    }

    const handleToggleBookmark = async () => {
        try {
            await evidenceApi.toggleBookmark(caseId, evidenceId)
            setEvidence(prev => ({ ...prev, isBookmarked: !prev.isBookmarked }))
            onUpdate?.()
        } catch (error) {
            toast.error('Failed to update bookmark')
        }
    }

    const handleMarkReviewed = async () => {
        try {
            await evidenceApi.update(caseId, evidenceId, { isReviewed: true })
            setEvidence(prev => ({ ...prev, isReviewed: true }))
            onUpdate?.()
            toast.success('Marked as reviewed')
        } catch (error) {
            toast.error('Failed to update')
        }
    }

    const handleSaveNotes = async () => {
        setSaving(true)
        try {
            await evidenceApi.update(caseId, evidenceId, { notes })
            toast.success('Notes saved')
            onUpdate?.()
        } catch (error) {
            toast.error('Failed to save notes')
        } finally {
            setSaving(false)
        }
    }

    const handleAddTag = async () => {
        if (!newTag.trim()) return

        const currentTags = evidence.tags || []
        const updatedTags = [...currentTags, newTag.trim()]

        try {
            await evidenceApi.update(caseId, evidenceId, { tags: updatedTags })
            setEvidence(prev => ({ ...prev, tags: updatedTags }))
            setNewTag('')
            onUpdate?.()
        } catch (error) {
            toast.error('Failed to add tag')
        }
    }

    const handleRemoveTag = async (tagToRemove) => {
        const updatedTags = (evidence.tags || []).filter(t => t !== tagToRemove)

        try {
            await evidenceApi.update(caseId, evidenceId, { tags: updatedTags })
            setEvidence(prev => ({ ...prev, tags: updatedTags }))
            onUpdate?.()
        } catch (error) {
            toast.error('Failed to remove tag')
        }
    }

    const formatDateTime = (dateString) => {
        if (!dateString) return 'N/A'
        return new Date(dateString).toLocaleString()
    }

    if (loading) {
        return (
            <div className="fixed inset-y-0 right-0 w-full max-w-lg bg-[var(--color-bg-secondary)] shadow-2xl z-50 flex items-center justify-center">
                <span className="spinner" />
            </div>
        )
    }

    if (!evidence) return null

    const { type, content, sender, receiver, timestamp, source, analysis = {} } = evidence
    const { priority = 'low', priorityScore = 0, flags = [], summary, sentiment, entities = [] } = analysis

    return (
        <>
            {/* Backdrop */}
            <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                className="fixed inset-0 bg-black/30 backdrop-blur-sm z-40"
                onClick={onClose}
            />

            {/* Panel */}
            <motion.div
                initial={{ x: '100%' }}
                animate={{ x: 0 }}
                exit={{ x: '100%' }}
                transition={{ type: 'spring', damping: 25, stiffness: 200 }}
                className="fixed inset-y-0 right-0 w-full max-w-lg bg-[var(--color-bg-secondary)] shadow-2xl z-50 flex flex-col"
            >
                {/* Header */}
                <div className="flex items-center justify-between px-6 py-4 border-b border-[var(--color-border-glass)]">
                    <h2 className="text-lg font-semibold text-[var(--color-text-primary)]">
                        Evidence Detail
                    </h2>
                    <button onClick={onClose} className="btn-ghost btn-icon p-2">
                        <X size={18} />
                    </button>
                </div>

                {/* Content */}
                <div className="flex-1 overflow-y-auto p-6 space-y-6">
                    {/* Type & Priority */}
                    <div className="flex items-center gap-2">
                        <PriorityBadge priority={priority} />
                        <TypeBadge type={type} />
                        {sentiment && (
                            <span className="badge badge-info">{sentiment}</span>
                        )}
                    </div>

                    {/* Metadata */}
                    <div className="grid grid-cols-2 gap-4 text-sm">
                        <div>
                            <span className="text-[var(--color-text-secondary)]">Timestamp</span>
                            <p className="text-[var(--color-text-primary)] m-0">{formatDateTime(timestamp)}</p>
                        </div>
                        <div>
                            <span className="text-[var(--color-text-secondary)]">Source</span>
                            <p className="text-[var(--color-text-primary)] m-0">{source || 'Unknown'}</p>
                        </div>
                        {sender && (
                            <div>
                                <span className="text-[var(--color-text-secondary)]">From</span>
                                <p className="text-[var(--color-text-primary)] m-0">{sender}</p>
                            </div>
                        )}
                        {receiver && (
                            <div>
                                <span className="text-[var(--color-text-secondary)]">To</span>
                                <p className="text-[var(--color-text-primary)] m-0">{receiver}</p>
                            </div>
                        )}
                    </div>

                    {/* Content */}
                    {content && (
                        <div>
                            <h4 className="text-sm font-medium text-[var(--color-text-secondary)] mb-2">Content</h4>
                            <div className="glass-card-static p-4">
                                <p className="text-sm text-[var(--color-text-primary)] m-0 whitespace-pre-wrap">
                                    {content}
                                </p>
                            </div>
                        </div>
                    )}

                    {/* AI Analysis */}
                    <div>
                        <h4 className="text-sm font-medium text-[var(--color-text-secondary)] mb-2">AI Analysis</h4>
                        <div className="glass-card-static p-4 space-y-3">
                            <div className="flex items-center justify-between">
                                <span className="text-sm text-[var(--color-text-secondary)]">Priority Score</span>
                                <span className="text-lg font-semibold text-[var(--color-text-primary)]">{priorityScore}/100</span>
                            </div>

                            {summary && (
                                <div>
                                    <span className="text-xs text-[var(--color-text-tertiary)]">Summary</span>
                                    <p className="text-sm text-[var(--color-text-primary)] m-0">{summary}</p>
                                </div>
                            )}

                            {flags.length > 0 && (
                                <div>
                                    <span className="text-xs text-[var(--color-text-tertiary)]">Flags</span>
                                    <div className="flex flex-wrap gap-1.5 mt-1">
                                        {flags.map((flag, i) => (
                                            <span
                                                key={i}
                                                className="px-2 py-0.5 text-xs rounded-full bg-[var(--color-accent-purple)]/10 text-[var(--color-accent-purple)]"
                                            >
                                                {flag}
                                            </span>
                                        ))}
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Tags */}
                    <div>
                        <h4 className="text-sm font-medium text-[var(--color-text-secondary)] mb-2">Tags</h4>
                        <div className="flex flex-wrap gap-2 mb-2">
                            {(evidence.tags || []).map((tag, i) => (
                                <span
                                    key={i}
                                    className="inline-flex items-center gap-1 px-2.5 py-1 text-xs rounded-full bg-[var(--color-accent-primary)]/10 text-[var(--color-accent-primary)]"
                                >
                                    {tag}
                                    <button
                                        onClick={() => handleRemoveTag(tag)}
                                        className="hover:text-[var(--color-accent-critical)]"
                                    >
                                        <X size={12} />
                                    </button>
                                </span>
                            ))}
                        </div>
                        <div className="flex gap-2">
                            <input
                                type="text"
                                value={newTag}
                                onChange={(e) => setNewTag(e.target.value)}
                                onKeyPress={(e) => e.key === 'Enter' && handleAddTag()}
                                className="input flex-1"
                                placeholder="Add tag..."
                            />
                            <Button size="sm" onClick={handleAddTag} disabled={!newTag.trim()}>
                                Add
                            </Button>
                        </div>
                    </div>

                    {/* Notes */}
                    <div>
                        <h4 className="text-sm font-medium text-[var(--color-text-secondary)] mb-2">Notes</h4>
                        <textarea
                            value={notes}
                            onChange={(e) => setNotes(e.target.value)}
                            className="input min-h-[100px] resize-y"
                            placeholder="Add investigation notes..."
                        />
                        <div className="flex justify-end mt-2">
                            <Button
                                size="sm"
                                variant="secondary"
                                onClick={handleSaveNotes}
                                loading={saving}
                            >
                                Save Notes
                            </Button>
                        </div>
                    </div>
                </div>

                {/* Footer Actions */}
                <div className="flex items-center gap-3 px-6 py-4 border-t border-[var(--color-border-glass)] bg-[var(--color-bg-glass)]">
                    <Button
                        variant={evidence.isBookmarked ? 'primary' : 'secondary'}
                        onClick={handleToggleBookmark}
                        icon={evidence.isBookmarked ? <BookmarkCheck size={16} /> : <Bookmark size={16} />}
                    >
                        {evidence.isBookmarked ? 'Bookmarked' : 'Bookmark'}
                    </Button>
                    {!evidence.isReviewed && (
                        <Button
                            variant="secondary"
                            onClick={handleMarkReviewed}
                            icon={<Check size={16} />}
                        >
                            Mark Reviewed
                        </Button>
                    )}
                </div>
            </motion.div>
        </>
    )
}

export default EvidenceDetail

import { Link, useLocation } from 'react-router-dom'
import { Menu, Moon, Sun, Search } from 'lucide-react'
import { useState } from 'react'

function Header({ darkMode, setDarkMode }) {
    const location = useLocation()
    const [searchOpen, setSearchOpen] = useState(false)

    return (
        <header className="glass-card-static sticky top-4 z-50 mx-auto mt-4 px-6 py-4 max-w-[1400px] w-[calc(100%-48px)] rounded-2xl shadow-lg border border-[var(--color-border-glass)] backdrop-blur-xl">
            <div className="flex items-center justify-between">
                {/* Logo */}
                <Link to="/" className="flex items-center gap-3 no-underline transition-transform hover:scale-105">
                    <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-[var(--color-accent-primary)] to-[var(--color-accent-purple)] flex items-center justify-center shadow-lg shadow-[var(--color-accent-primary)]/20">
                        <span className="text-xl text-white">≡ƒÑé</span>
                    </div>
                    <div>
                        <h1 className="text-xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-[var(--color-text-primary)] to-[var(--color-text-secondary)] m-0 tracking-tight">
                            GLASSBOX
                        </h1>
                        <p className="text-xs text-[var(--color-accent-primary)] m-0 tracking-widest uppercase font-semibold opacity-80">
                            Forensic Triage
                        </p>
                    </div>
                </Link>

                {/* Right Actions */}
                <div className="flex items-center gap-2">
                    {/* Search (expandable) */}
                    <div className={`relative transition-all duration-300 ${searchOpen ? 'w-64' : 'w-10'}`}>
                        {searchOpen ? (
                            <input
                                type="text"
                                placeholder="Search cases..."
                                className="input pr-10"
                                autoFocus
                                onBlur={() => setSearchOpen(false)}
                            />
                        ) : null}
                        <button
                            onClick={() => setSearchOpen(!searchOpen)}
                            className={`btn-ghost btn-icon ${searchOpen ? 'absolute right-1 top-1/2 -translate-y-1/2' : ''}`}
                        >
                            <Search size={18} />
                        </button>
                    </div>

                    {/* Theme Toggle */}
                    <button
                        onClick={() => setDarkMode(!darkMode)}
                        className="btn-ghost btn-icon"
                        title={darkMode ? 'Switch to light mode' : 'Switch to dark mode'}
                    >
                        {darkMode ? <Sun size={18} /> : <Moon size={18} />}
                    </button>
                </div>
            </div>
        </header>
    )
}

export default Header

import { clsx } from 'clsx'
import { twMerge } from 'tailwind-merge'
import { motion } from 'framer-motion'

function GlassCard({
    children,
    className,
    hover = true,
    padding = 'md',
    ...props
}) {
    const paddingClasses = {
        none: '',
        sm: 'p-4',
        md: 'p-6',
        lg: 'p-8',
        xl: 'p-10'
    }

    const baseClasses = twMerge(
        clsx(
            hover ? 'glass-card' : 'glass-card-static',
            paddingClasses[padding],
            className
        )
    )

    if (hover) {
        return (
            <motion.div
                className={baseClasses}
                whileHover={{ y: -4, scale: 1.01 }}
                transition={{ type: "spring", stiffness: 400, damping: 25 }}
                {...props}
            >
                {children}
            </motion.div>
        )
    }

    return (
        <div className={baseClasses} {...props}>
            {children}
        </div>
    )
}

export default GlassCard

import { useEffect } from 'react'
import { X } from 'lucide-react'
import { motion, AnimatePresence } from 'framer-motion'

function Modal({ isOpen, onClose, title, children, size = 'md' }) {
    // Close on escape key
    useEffect(() => {
        const handleEscape = (e) => {
            if (e.key === 'Escape') onClose()
        }

        if (isOpen) {
            document.addEventListener('keydown', handleEscape)
            document.body.style.overflow = 'hidden'
        }

        return () => {
            document.removeEventListener('keydown', handleEscape)
            document.body.style.overflow = ''
        }
    }, [isOpen, onClose])

    const sizeClasses = {
        sm: 'max-w-md',
        md: 'max-w-lg',
        lg: 'max-w-2xl',
        xl: 'max-w-4xl',
    }

    return (
        <AnimatePresence>
            {isOpen && (
                <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
                    {/* Backdrop */}
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        onClick={onClose}
                        className="absolute inset-0 bg-black/40 backdrop-blur-sm"
                    />

                    {/* Modal */}
                    <motion.div
                        initial={{ opacity: 0, scale: 0.95, y: 20 }}
                        animate={{ opacity: 1, scale: 1, y: 0 }}
                        exit={{ opacity: 0, scale: 0.95, y: 20 }}
                        transition={{ duration: 0.2 }}
                        className={`relative w-full ${sizeClasses[size]} max-h-[90vh] overflow-hidden bg-[var(--color-bg-secondary)] rounded-2xl shadow-2xl`}
                    >
                        {/* Header */}
                        {title && (
                            <div className="flex items-center justify-between px-6 py-4 border-b border-[var(--color-border-glass)]">
                                <h2 className="text-lg font-semibold text-[var(--color-text-primary)]">
                                    {title}
                                </h2>
                                <button
                                    onClick={onClose}
                                    className="btn-ghost btn-icon p-2 -mr-2"
                                >
                                    <X size={18} />
                                </button>
                            </div>
                        )}

                        {/* Content */}
                        <div className="overflow-y-auto max-h-[calc(90vh-80px)]">
                            {children}
                        </div>
                    </motion.div>
                </div>
            )}
        </AnimatePresence>
    )
}

export default Modal

import { createContext, useContext, useState, useCallback } from 'react'
import { X, CheckCircle, AlertCircle, Info, AlertTriangle } from 'lucide-react'

const ToastContext = createContext(null)

const TOAST_DURATION = 4000

const icons = {
    success: CheckCircle,
    error: AlertCircle,
    warning: AlertTriangle,
    info: Info,
}

const colors = {
    success: 'var(--color-accent-success)',
    error: 'var(--color-accent-critical)',
    warning: 'var(--color-accent-warning)',
    info: 'var(--color-accent-primary)',
}

export function ToastProvider({ children }) {
    const [toasts, setToasts] = useState([])

    const addToast = useCallback((message, type = 'info') => {
        const id = Date.now()
        setToasts(prev => [...prev, { id, message, type }])

        setTimeout(() => {
            setToasts(prev => prev.filter(t => t.id !== id))
        }, TOAST_DURATION)
    }, [])

    const removeToast = useCallback((id) => {
        setToasts(prev => prev.filter(t => t.id !== id))
    }, [])

    const toast = {
        success: (msg) => addToast(msg, 'success'),
        error: (msg) => addToast(msg, 'error'),
        warning: (msg) => addToast(msg, 'warning'),
        info: (msg) => addToast(msg, 'info'),
    }

    return (
        <ToastContext.Provider value={toast}>
            {children}
            <ToastContainer toasts={toasts} removeToast={removeToast} />
        </ToastContext.Provider>
    )
}

function ToastContainer({ toasts, removeToast }) {
    return (
        <div className="fixed bottom-6 right-6 z-[200] flex flex-col gap-3">
            {toasts.map(toast => (
                <Toast key={toast.id} toast={toast} onClose={() => removeToast(toast.id)} />
            ))}
        </div>
    )
}

function Toast({ toast, onClose }) {
    const Icon = icons[toast.type]
    const color = colors[toast.type]

    return (
        <div
            className="glass-card-static flex items-center gap-3 px-4 py-3 min-w-[300px] animate-[slideUp_0.25s_ease]"
            style={{ borderLeft: `3px solid ${color}` }}
        >
            <Icon size={18} style={{ color }} />
            <p className="flex-1 text-sm text-[var(--color-text-primary)] m-0">{toast.message}</p>
            <button onClick={onClose} className="btn-ghost btn-icon p-1">
                <X size={14} />
            </button>
        </div>
    )
}

export function useToast() {
    const context = useContext(ToastContext)
    if (!context) {
        throw new Error('useToast must be used within ToastProvider')
    }
    return context
}

export default ToastProvider

import { useState, useEffect, useCallback } from 'react'
import { useParams, Link, useNavigate } from 'react-router-dom'
import {
    ArrowLeft, Upload, Zap, Clock, BarChart2, Users,
    Edit, Trash2, MoreVertical, FileText, AlertTriangle,
    MessageSquare, Phone, MapPin, User, Smartphone
} from 'lucide-react'
import { motion, AnimatePresence } from 'framer-motion'
import GlassCard from '../components/ui/GlassCard'
import Button from '../components/ui/Button'
import Tabs from '../components/ui/Tabs'
import Modal from '../components/ui/Modal'
import FileUpload from '../components/ui/FileUpload'
import { StatusBadge } from '../components/ui/Badges'
import CaseForm from '../components/cases/CaseForm'
import EvidenceCard from '../components/evidence/EvidenceCard'
import EvidenceDetail from '../components/evidence/EvidenceDetail'
import EvidenceFilters from '../components/evidence/EvidenceFilters'
import { casesApi, evidenceApi, uploadApi } from '../services/api'
import { useToast } from '../components/ui/Toast'

function CaseDetail() {
    const { id } = useParams()
    const navigate = useNavigate()
    const toast = useToast()

    // Case data
    const [caseData, setCaseData] = useState(null)
    const [loading, setLoading] = useState(true)
    const [summary, setSummary] = useState([])

    // Evidence data
    const [evidence, setEvidence] = useState([])
    const [evidenceLoading, setEvidenceLoading] = useState(false)
    const [pagination, setPagination] = useState({ page: 1, total: 0, pages: 1 })
    const [filters, setFilters] = useState({})
    const [sources, setSources] = useState([])
    const [tags, setTags] = useState([])

    // UI state
    const [activeTab, setActiveTab] = useState('all')
    const [selectedEvidence, setSelectedEvidence] = useState(null)
    const [showUpload, setShowUpload] = useState(false)
    const [showEdit, setShowEdit] = useState(false)
    const [analyzing, setAnalyzing] = useState(false)
    const [updating, setUpdating] = useState(false)

    // Load case data
    const loadCase = useCallback(async () => {
        try {
            const [caseResult, summaryResult, sourcesResult, tagsResult] = await Promise.all([
                casesApi.get(id),
                evidenceApi.getSummary(id),
                evidenceApi.getSources(id),
                evidenceApi.getTags(id),
            ])

            setCaseData(caseResult.data)
            setSummary(summaryResult.data || [])
            setSources(sourcesResult.data || [])
            setTags(tagsResult.data || [])
        } catch (error) {
            toast.error('Failed to load case')
            navigate('/')
        } finally {
            setLoading(false)
        }
    }, [id, navigate, toast])

    // Load evidence
    const loadEvidence = useCallback(async () => {
        setEvidenceLoading(true)
        try {
            let result

            if (activeTab === 'high-priority') {
                result = await evidenceApi.getHighPriority(id, { ...filters, page: pagination.page })
            } else if (activeTab === 'bookmarked') {
                result = await evidenceApi.getBookmarked(id)
                // Wrap in standard format
                result = { data: result.data, pagination: { page: 1, total: result.total, pages: 1 } }
            } else {
                const tabFilters = activeTab === 'unreviewed' ? { ...filters, reviewed: 'false' } : filters
                result = await evidenceApi.list(id, { ...tabFilters, page: pagination.page })
            }

            setEvidence(result.data || [])
            if (result.pagination) {
                setPagination(result.pagination)
            }
        } catch (error) {
            toast.error('Failed to load evidence')
        } finally {
            setEvidenceLoading(false)
        }
    }, [id, activeTab, filters, pagination.page, toast])

    useEffect(() => {
        loadCase()
    }, [loadCase])

    useEffect(() => {
        if (caseData) {
            loadEvidence()
        }
    }, [caseData, loadEvidence])

    // Handlers
    const handleUpload = async (file) => {
        try {
            const result = await uploadApi.upload(id, file)
            toast.success('File uploaded! Processing...')

            // Poll for status
            const pollStatus = async () => {
                const status = await uploadApi.getStatus(id, result.data.jobId)
                if (status.data.status === 'completed') {
                    toast.success(`Imported ${status.data.savedRecords} evidence items`)
                    loadCase()
                    loadEvidence()
                } else if (status.data.status === 'failed') {
                    toast.error('Upload processing failed')
                } else {
                    setTimeout(pollStatus, 2000)
                }
            }
            setTimeout(pollStatus, 2000)

            setShowUpload(false)
        } catch (error) {
            toast.error('Upload failed')
        }
    }

    const handleAnalyze = async () => {
        setAnalyzing(true)
        try {
            await casesApi.analyze(id)
            toast.success('Analysis started!')

            // Poll for completion
            const pollStatus = async () => {
                const status = await casesApi.getAnalysisStatus(id)
                const latestJob = status.data?.[0]
                if (latestJob?.status === 'completed') {
                    toast.success('Analysis complete!')
                    loadEvidence()
                    setAnalyzing(false)
                } else if (latestJob?.status === 'failed') {
                    toast.error('Analysis failed')
                    setAnalyzing(false)
                } else {
                    setTimeout(pollStatus, 3000)
                }
            }
            setTimeout(pollStatus, 3000)
        } catch (error) {
            toast.error(error.message || 'Failed to start analysis')
            setAnalyzing(false)
        }
    }

    const handleUpdateCase = async (data) => {
        setUpdating(true)
        try {
            await casesApi.update(id, data)
            toast.success('Case updated')
            setShowEdit(false)
            loadCase()
        } catch (error) {
            toast.error('Failed to update case')
        } finally {
            setUpdating(false)
        }
    }

    const handleDeleteCase = async () => {
        if (!confirm('Are you sure you want to delete this case and all its evidence?')) return

        try {
            await casesApi.delete(id)
            toast.success('Case deleted')
            navigate('/')
        } catch (error) {
            toast.error('Failed to delete case')
        }
    }

    const handleBookmark = async (evidenceId) => {
        try {
            await evidenceApi.toggleBookmark(id, evidenceId)
            setEvidence(prev => prev.map(e =>
                e._id === evidenceId ? { ...e, isBookmarked: !e.isBookmarked } : e
            ))
        } catch (error) {
            toast.error('Failed to update bookmark')
        }
    }

    const tabs = [
        { id: 'all', label: 'All', count: caseData?.evidenceCount },
        { id: 'high-priority', label: 'High Priority', count: caseData?.highPriorityCount },
        { id: 'bookmarked', label: 'Bookmarked' },
        { id: 'unreviewed', label: 'Unreviewed' },
    ]

    // Evidence type icons
    const typeIcons = {
        message: <MessageSquare size={14} />,
        call: <Phone size={14} />,
        location: <MapPin size={14} />,
        contact: <User size={14} />,
    }

    if (loading) {
        return (
            <div className="flex items-center justify-center min-h-[400px]">
                <span className="spinner" style={{ width: 32, height: 32 }} />
            </div>
        )
    }

    if (!caseData) return null

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex items-start justify-between">
                <div className="flex items-center gap-4">
                    <Link to="/" className="btn-ghost btn-icon p-2">
                        <ArrowLeft size={20} />
                    </Link>
                    <div>
                        <div className="flex items-center gap-3 mb-1">
                            <h1 className="text-3xl font-extrabold text-transparent bg-clip-text bg-gradient-to-r from-[var(--color-text-primary)] to-[var(--color-accent-primary)] tracking-tight">
                                {caseData.caseName}
                            </h1>
                            <StatusBadge status={caseData.status} />
                        </div>
                        {caseData.caseNumber && (
                            <p className="text-[var(--color-text-secondary)]">
                                Case #{caseData.caseNumber}
                                {caseData.investigator && ` ΓÇó ${caseData.investigator}`}
                            </p>
                        )}
                    </div>
                </div>

                <div className="flex items-center gap-2">
                    <Button variant="ghost" icon={<Edit size={16} />} onClick={() => setShowEdit(true)}>
                        Edit
                    </Button>
                    <Button variant="ghost" icon={<Trash2 size={16} />} onClick={handleDeleteCase}>
                        Delete
                    </Button>
                </div>
            </div>

            {/* Case Info & Summary Row */}
            <div className="grid grid-cols-3 gap-4">
                {/* Case Info */}
                <GlassCard hover={false} className="relative overflow-hidden group">
                    <div className="absolute inset-0 bg-gradient-to-br from-[var(--color-accent-primary)]/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />
                    <h3 className="text-sm font-bold text-[var(--color-text-tertiary)] mb-4 uppercase tracking-widest border-b border-[var(--color-border-subtle)] pb-2 flex items-center gap-2">
                        <Smartphone size={16} className="text-[var(--color-accent-primary)]" /> Device Information
                    </h3>
                    <div className="space-y-2 text-sm">
                        {caseData.deviceInfo?.deviceType && (
                            <div className="flex justify-between">
                                <span className="text-[var(--color-text-secondary)]">Device</span>
                                <span className="text-[var(--color-text-primary)]">{caseData.deviceInfo.deviceType}</span>
                            </div>
                        )}
                        {caseData.deviceInfo?.owner && (
                            <div className="flex justify-between">
                                <span className="text-[var(--color-text-secondary)]">Owner</span>
                                <span className="text-[var(--color-text-primary)]">{caseData.deviceInfo.owner}</span>
                            </div>
                        )}
                        {caseData.deviceInfo?.imei && (
                            <div className="flex justify-between">
                                <span className="text-[var(--color-text-secondary)]">IMEI</span>
                                <span className="text-[var(--color-text-primary)] font-mono text-xs">{caseData.deviceInfo.imei}</span>
                            </div>
                        )}
                        {caseData.uploadedFiles?.length > 0 && (
                            <div className="flex justify-between">
                                <span className="text-[var(--color-text-secondary)]">Files</span>
                                <span className="text-[var(--color-text-primary)]">{caseData.uploadedFiles.length} uploaded</span>
                            </div>
                        )}
                    </div>
                </GlassCard>

                {/* Evidence Summary */}
                <GlassCard hover={false} className="col-span-2 relative overflow-hidden group">
                    <div className="absolute inset-0 bg-gradient-to-br from-[var(--color-accent-purple)]/5 to-[var(--color-accent-primary)]/5 opacity-0 group-hover:opacity-100 transition-opacity" />
                    <h3 className="text-sm font-bold text-[var(--color-text-tertiary)] mb-4 uppercase tracking-widest border-b border-[var(--color-border-subtle)] pb-2 flex items-center gap-2">
                        <BarChart2 size={16} className="text-[var(--color-accent-purple)]" /> Evidence Breakdown
                    </h3>
                    <div className="grid grid-cols-5 gap-3 pt-2">
                        {['message', 'call', 'location', 'contact', 'other'].map(type => {
                            const typeData = summary.find(s => s.type === type) || { count: 0, highPriority: 0 }
                            return (
                                <div key={type} className="text-center">
                                    <div className="text-xl font-semibold text-[var(--color-text-primary)]">
                                        {typeData.count}
                                    </div>
                                    <div className="text-xs text-[var(--color-text-secondary)] capitalize">
                                        {type}s
                                    </div>
                                    {typeData.highPriority > 0 && (
                                        <div className="text-xs text-[var(--color-accent-warning)]">
                                            {typeData.highPriority} high
                                        </div>
                                    )}
                                </div>
                            )
                        })}
                    </div>
                </GlassCard>
            </div>

            {/* Actions Row */}
            <div className="flex items-center gap-3">
                <Button icon={<Upload size={16} />} onClick={() => setShowUpload(true)}>
                    Upload File
                </Button>
                <Button
                    variant="secondary"
                    icon={<Zap size={16} />}
                    onClick={handleAnalyze}
                    loading={analyzing}
                    disabled={analyzing}
                >
                    {analyzing ? 'Analyzing...' : 'Run Analysis'}
                </Button>
                <Link to={`/case/${id}/timeline`}>
                    <Button variant="ghost" icon={<BarChart2 size={16} />}>
                        Timeline
                    </Button>
                </Link>
                <Link to={`/case/${id}/contacts`}>
                    <Button variant="ghost" icon={<Users size={16} />}>
                        Contacts
                    </Button>
                </Link>
            </div>

            {/* Evidence Section */}
            <GlassCard hover={false} padding="lg">
                <div className="flex items-center justify-between mb-4">
                    <h2 className="text-lg font-semibold text-[var(--color-text-primary)]">
                        Evidence Feed
                    </h2>
                    <Tabs tabs={tabs} activeTab={activeTab} onChange={setActiveTab} />
                </div>

                {/* Filters */}
                <div className="mb-4">
                    <EvidenceFilters
                        filters={filters}
                        onFilterChange={setFilters}
                        sources={sources}
                        tags={tags}
                    />
                </div>

                {/* Evidence List */}
                {evidenceLoading ? (
                    <div className="space-y-3">
                        {[1, 2, 3].map(i => (
                            <div key={i} className="skeleton h-24 rounded-xl" />
                        ))}
                    </div>
                ) : evidence.length === 0 ? (
                    <div className="text-center py-12">
                        <FileText size={48} className="mx-auto mb-4 text-[var(--color-text-tertiary)]" />
                        <p className="text-[var(--color-text-secondary)]">
                            No evidence found. Upload a forensic export to get started.
                        </p>
                    </div>
                ) : (
                    <motion.div layout className="space-y-3">
                        <AnimatePresence>
                            {evidence.map((item) => (
                                <motion.div
                                    key={item._id}
                                    layout
                                    initial={{ opacity: 0, y: 10 }}
                                    animate={{ opacity: 1, y: 0 }}
                                    exit={{ opacity: 0, y: -10 }}
                                >
                                    <EvidenceCard
                                        evidence={item}
                                        onClick={setSelectedEvidence}
                                        onBookmark={handleBookmark}
                                    />
                                </motion.div>
                            ))}
                        </AnimatePresence>
                    </motion.div>
                )}

                {/* Pagination */}
                {pagination.pages > 1 && (
                    <div className="flex items-center justify-center gap-2 mt-6">
                        <Button
                            variant="ghost"
                            size="sm"
                            disabled={pagination.page === 1}
                            onClick={() => setPagination(p => ({ ...p, page: p.page - 1 }))}
                        >
                            Previous
                        </Button>
                        <span className="text-sm text-[var(--color-text-secondary)]">
                            Page {pagination.page} of {pagination.pages}
                        </span>
                        <Button
                            variant="ghost"
                            size="sm"
                            disabled={pagination.page === pagination.pages}
                            onClick={() => setPagination(p => ({ ...p, page: p.page + 1 }))}
                        >
                            Next
                        </Button>
                    </div>
                )}
            </GlassCard>

            {/* Evidence Detail Panel */}
            <AnimatePresence>
                {selectedEvidence && (
                    <EvidenceDetail
                        caseId={id}
                        evidenceId={selectedEvidence}
                        onClose={() => setSelectedEvidence(null)}
                        onUpdate={loadEvidence}
                    />
                )}
            </AnimatePresence>

            {/* Upload Modal */}
            <Modal
                isOpen={showUpload}
                onClose={() => setShowUpload(false)}
                title="Upload Forensic Export"
            >
                <div className="p-6">
                    <FileUpload onUpload={handleUpload} />
                    <p className="text-sm text-[var(--color-text-secondary)] mt-4">
                        Supports forensic exports (CSV/Excel), screenshots (OCR), and voice notes (Transcription).
                    </p>
                </div>
            </Modal>

            {/* Edit Case Modal */}
            <Modal
                isOpen={showEdit}
                onClose={() => setShowEdit(false)}
                title="Edit Case"
                size="lg"
            >
                <CaseForm
                    initialData={caseData}
                    onSubmit={handleUpdateCase}
                    onCancel={() => setShowEdit(false)}
                    loading={updating}
                />
            </Modal>
        </div>
    )
}

export default CaseDetail

import { useState, useEffect, useRef } from 'react'
import { useParams, Link } from 'react-router-dom'
import { ArrowLeft, Users, MessageSquare, Phone } from 'lucide-react'
import { motion } from 'framer-motion'
import GlassCard from '../components/ui/GlassCard'
import { casesApi } from '../services/api'
import { useToast } from '../components/ui/Toast'

function Contacts() {
    const { id } = useParams()
    const toast = useToast()
    const hasFetched = useRef(false)

    const [loading, setLoading] = useState(true)
    const [caseData, setCaseData] = useState(null)
    const [contacts, setContacts] = useState([])

    useEffect(() => {
        if (hasFetched.current) return
        hasFetched.current = true

        const loadData = async () => {
            setLoading(true)
            try {
                const [caseResult, contactsResult] = await Promise.all([
                    casesApi.get(id),
                    casesApi.getContacts(id, { limit: 50 }),
                ])

                setCaseData(caseResult.data)
                // Backend returns { keyContacts, totalPairs }
                const contactsData = contactsResult.data?.keyContacts || contactsResult.data || []
                setContacts(contactsData)
            } catch (error) {
                console.error('Contacts error:', error)
                toast.error('Failed to load contacts')
            } finally {
                setLoading(false)
            }
        }

        loadData()
    }, [id, toast])

    // Find max for bar scaling - use totalMessages from backend
    const maxMessages = Math.max(...contacts.map(c => c.totalMessages || c.messageCount || c.count || 0), 1)

    // Stat cards
    const totalContacts = contacts.length
    const totalMessages = contacts.reduce((sum, c) => sum + (c.totalMessages || c.messageCount || c.count || 0), 0)

    if (loading) {
        return (
            <div className="flex items-center justify-center min-h-[400px]">
                <span className="spinner" style={{ width: 32, height: 32 }} />
            </div>
        )
    }

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex items-center gap-4">
                <Link to={`/case/${id}`} className="btn-ghost btn-icon p-2">
                    <ArrowLeft size={20} />
                </Link>
                <div>
                    <h1 className="text-2xl font-bold text-[var(--color-text-primary)]">
                        Contact Network
                    </h1>
                    <p className="text-[var(--color-text-secondary)]">
                        {caseData?.caseName} ΓÇö Communication patterns
                    </p>
                </div>
            </div>

            {/* Stats */}
            <div className="grid grid-cols-2 gap-4">
                <GlassCard hover={false} className="flex items-center gap-4">
                    <div className="w-12 h-12 rounded-xl bg-[var(--color-accent-primary)]/10 flex items-center justify-center">
                        <Users size={24} className="text-[var(--color-accent-primary)]" />
                    </div>
                    <div>
                        <div className="text-2xl font-bold text-[var(--color-text-primary)]">
                            {totalContacts}
                        </div>
                        <div className="text-sm text-[var(--color-text-secondary)]">
                            Unique Contacts
                        </div>
                    </div>
                </GlassCard>

                <GlassCard hover={false} className="flex items-center gap-4">
                    <div className="w-12 h-12 rounded-xl bg-[var(--color-accent-purple)]/10 flex items-center justify-center">
                        <MessageSquare size={24} className="text-[var(--color-accent-purple)]" />
                    </div>
                    <div>
                        <div className="text-2xl font-bold text-[var(--color-text-primary)]">
                            {totalMessages.toLocaleString()}
                        </div>
                        <div className="text-sm text-[var(--color-text-secondary)]">
                            Total Interactions
                        </div>
                    </div>
                </GlassCard>
            </div>

            {/* Contacts List */}
            <GlassCard hover={false} padding="lg">
                <h2 className="text-lg font-semibold text-[var(--color-text-primary)] mb-4">
                    Top Contacts
                </h2>

                {contacts.length === 0 ? (
                    <div className="text-center py-12">
                        <Users size={48} className="mx-auto mb-4 text-[var(--color-text-tertiary)]" />
                        <p className="text-[var(--color-text-secondary)]">
                            No contact data available. Upload evidence to see contact patterns.
                        </p>
                    </div>
                ) : (
                    <div className="space-y-3">
                        {contacts.map((contact, index) => {
                            const messageCount = contact.totalMessages || contact.messageCount || contact.count || 0
                            const barWidth = (messageCount / maxMessages) * 100
                            const displayName = contact.name || contact.contactName || contact.contact || 'Unknown'

                            return (
                                <motion.div
                                    key={contact.name || contact._id || index}
                                    initial={{ opacity: 0, x: -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    transition={{ delay: index * 0.05 }}
                                    className="group p-4 rounded-xl hover:bg-[var(--color-bg-glass)] transition-colors cursor-pointer"
                                >
                                    <div className="flex items-center justify-between mb-2">
                                        <div className="flex items-center gap-3">
                                            <div className="w-10 h-10 rounded-full bg-[var(--color-accent-primary)]/10 flex items-center justify-center text-[var(--color-accent-primary)] font-medium">
                                                {displayName[0].toUpperCase()}
                                            </div>
                                            <div>
                                                <div className="font-medium text-[var(--color-text-primary)]">
                                                    {displayName}
                                                </div>
                                                {contact.uniqueContacts > 0 && (
                                                    <div className="text-xs text-[var(--color-text-secondary)]">
                                                        {contact.uniqueContacts} contacts
                                                    </div>
                                                )}
                                            </div>
                                        </div>
                                        <div className="text-right">
                                            <div className="font-semibold text-[var(--color-text-primary)]">
                                                {messageCount.toLocaleString()}
                                            </div>
                                            <div className="text-xs text-[var(--color-text-secondary)]">
                                                messages
                                            </div>
                                        </div>
                                    </div>

                                    {/* Progress Bar */}
                                    <div className="h-2 bg-[var(--color-border-glass)] rounded-full overflow-hidden">
                                        <motion.div
                                            initial={{ width: 0 }}
                                            animate={{ width: `${barWidth}%` }}
                                            transition={{ duration: 0.5, delay: index * 0.05 }}
                                            className="h-full rounded-full"
                                            style={{
                                                background: `linear-gradient(90deg, var(--color-accent-primary), var(--color-accent-purple))`,
                                            }}
                                        />
                                    </div>
                                </motion.div>
                            )
                        })}
                    </div>
                )}

                <p className="text-xs text-[var(--color-text-tertiary)] text-center mt-4">
                    Click a contact to filter evidence by this sender/receiver
                </p>
            </GlassCard>
        </div>
    )
}

export default Contacts

import { useState, useEffect, useCallback } from 'react'
import { Plus, Search, RefreshCw } from 'lucide-react'
import { motion } from 'framer-motion'
import GlassCard from '../components/ui/GlassCard'
import Button from '../components/ui/Button'
import Modal from '../components/ui/Modal'
import CaseCard from '../components/cases/CaseCard'
import CaseForm from '../components/cases/CaseForm'
import { casesApi } from '../services/api'
import { useToast } from '../components/ui/Toast'

function Dashboard() {
    const [cases, setCases] = useState([])
    const [loading, setLoading] = useState(true)
    const [search, setSearch] = useState('')
    const [statusFilter, setStatusFilter] = useState('')
    const [showNewCase, setShowNewCase] = useState(false)
    const [creating, setCreating] = useState(false)
    const toast = useToast()

    // Stats
    const [stats, setStats] = useState({
        totalCases: 0,
        activeCases: 0,
        totalEvidence: 0,
        highPriority: 0,
    })

    const loadCases = useCallback(async () => {
        setLoading(true)
        try {
            const params = {}
            if (search) params.search = search
            if (statusFilter) params.status = statusFilter

            const result = await casesApi.list(params)
            setCases(result.data || [])

            // Calculate stats
            const active = (result.data || []).filter(c => c.status === 'active').length
            const totalEvidence = (result.data || []).reduce((sum, c) => sum + (c.evidenceCount || 0), 0)
            const highPriority = (result.data || []).reduce((sum, c) => sum + (c.highPriorityCount || 0), 0)

            setStats({
                totalCases: result.pagination?.total || result.data?.length || 0,
                activeCases: active,
                totalEvidence,
                highPriority,
            })
        } catch (error) {
            toast.error('Failed to load cases')
        } finally {
            setLoading(false)
        }
    }, [search, statusFilter, toast])

    useEffect(() => {
        loadCases()
    }, [loadCases])

    const handleCreateCase = async (data) => {
        setCreating(true)
        try {
            await casesApi.create(data)
            toast.success('Case created successfully')
            setShowNewCase(false)
            loadCases()
        } catch (error) {
            toast.error(error.message || 'Failed to create case')
        } finally {
            setCreating(false)
        }
    }

    // Stat card animation variants
    const containerVariants = {
        hidden: { opacity: 0 },
        show: {
            opacity: 1,
            transition: { staggerChildren: 0.1 }
        }
    }

    const itemVariants = {
        hidden: { opacity: 0, y: 20 },
        show: { opacity: 1, y: 0 }
    }

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex items-end justify-between mb-8">
                <div>
                    <motion.h1
                        initial={{ opacity: 0, x: -20 }}
                        animate={{ opacity: 1, x: 0 }}
                        className="text-4xl font-extrabold text-transparent bg-clip-text bg-gradient-to-r from-[var(--color-text-primary)] to-[var(--color-accent-primary)] mb-2 tracking-tight"
                    >
                        Dashboard
                    </motion.h1>
                    <motion.p
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        transition={{ delay: 0.1 }}
                        className="text-[var(--color-text-secondary)] font-medium text-lg"
                    >
                        Forensic triage command center
                    </motion.p>
                </div>
                <Button icon={<Plus size={18} />} onClick={() => setShowNewCase(true)}>
                    New Case
                </Button>
            </div>

            {/* Stats Grid */}
            <motion.div
                variants={containerVariants}
                initial="hidden"
                animate="show"
                className="grid grid-cols-4 gap-4"
            >
                <motion.div variants={itemVariants}>
                    <GlassCard hover={false} className="text-center flex flex-col items-center justify-center min-h-[120px] relative overflow-hidden group">
                        <div className="absolute inset-0 bg-gradient-to-br from-[var(--color-accent-primary)]/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />
                        <div className="text-4xl font-black text-[var(--color-text-primary)] mb-2 tracking-tight">
                            {stats.totalCases}
                        </div>
                        <div className="text-sm font-semibold text-[var(--color-text-tertiary)] uppercase tracking-wider">Total Cases</div>
                    </GlassCard>
                </motion.div>

                <motion.div variants={itemVariants}>
                    <GlassCard hover={false} className="text-center flex flex-col items-center justify-center min-h-[120px] relative overflow-hidden group">
                        <div className="absolute inset-0 bg-gradient-to-br from-[var(--color-accent-success)]/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />
                        <div className="text-4xl font-black text-[var(--color-accent-success)] mb-2 drop-shadow-[0_0_15px_rgba(16,185,129,0.3)] tracking-tight">
                            {stats.activeCases}
                        </div>
                        <div className="text-sm font-semibold text-[var(--color-text-tertiary)] uppercase tracking-wider">Active Cases</div>
                    </GlassCard>
                </motion.div>

                <motion.div variants={itemVariants}>
                    <GlassCard hover={false} className="text-center flex flex-col items-center justify-center min-h-[120px] relative overflow-hidden group">
                        <div className="absolute inset-0 bg-gradient-to-br from-[var(--color-accent-primary)]/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />
                        <div className="text-4xl font-black text-[var(--color-text-primary)] mb-2 tracking-tight">
                            {stats.totalEvidence.toLocaleString()}
                        </div>
                        <div className="text-sm font-semibold text-[var(--color-text-tertiary)] uppercase tracking-wider">Evidence Items</div>
                    </GlassCard>
                </motion.div>

                <motion.div variants={itemVariants}>
                    <GlassCard hover={false} className="text-center flex flex-col items-center justify-center min-h-[120px] relative overflow-hidden group">
                        <div className="absolute inset-0 bg-gradient-to-br from-[var(--color-accent-critical)]/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />
                        <div className="text-4xl font-black text-[var(--color-accent-critical)] mb-2 drop-shadow-[0_0_15px_rgba(239,68,68,0.3)] tracking-tight">
                            {stats.highPriority}
                        </div>
                        <div className="text-sm font-semibold text-[var(--color-text-tertiary)] uppercase tracking-wider">High Priority</div>
                    </GlassCard>
                </motion.div>
            </motion.div>

            {/* Cases Section */}
            <GlassCard hover={false} padding="lg">
                <div className="flex items-center justify-between mb-4">
                    <h2 className="text-lg font-semibold text-[var(--color-text-primary)]">
                        Recent Cases
                    </h2>
                    <button
                        onClick={loadCases}
                        className="btn-ghost btn-icon p-2"
                        title="Refresh"
                    >
                        <RefreshCw size={16} className={loading ? 'animate-spin' : ''} />
                    </button>
                </div>

                {/* Filters */}
                <div className="flex items-center gap-3 mb-4">
                    <div className="relative flex-1 max-w-md">
                        <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-[var(--color-text-tertiary)]" />
                        <input
                            type="text"
                            placeholder="Search cases..."
                            value={search}
                            onChange={(e) => setSearch(e.target.value)}
                            className="input pl-10"
                        />
                    </div>
                    <select
                        value={statusFilter}
                        onChange={(e) => setStatusFilter(e.target.value)}
                        className="input w-auto"
                    >
                        <option value="">All Status</option>
                        <option value="active">Active</option>
                        <option value="archived">Archived</option>
                        <option value="closed">Closed</option>
                    </select>
                </div>

                {/* Cases List */}
                {loading ? (
                    <div className="grid grid-cols-2 gap-4">
                        {[1, 2, 3, 4].map(i => (
                            <div key={i} className="skeleton h-32 rounded-xl" />
                        ))}
                    </div>
                ) : cases.length === 0 ? (
                    <div className="text-center py-12">
                        <p className="text-[var(--color-text-secondary)] mb-4">
                            No cases found. Create your first case to get started.
                        </p>
                        <Button onClick={() => setShowNewCase(true)}>
                            Create Case
                        </Button>
                    </div>
                ) : (
                    <motion.div
                        variants={containerVariants}
                        initial="hidden"
                        animate="show"
                        className="grid grid-cols-2 gap-4"
                    >
                        {cases.map((caseData) => (
                            <motion.div key={caseData._id} variants={itemVariants}>
                                <CaseCard caseData={caseData} />
                            </motion.div>
                        ))}
                    </motion.div>
                )}
            </GlassCard>

            {/* New Case Modal */}
            <Modal
                isOpen={showNewCase}
                onClose={() => setShowNewCase(false)}
                title="Create New Case"
                size="lg"
            >
                <CaseForm
                    onSubmit={handleCreateCase}
                    onCancel={() => setShowNewCase(false)}
                    loading={creating}
                />
            </Modal>
        </div>
    )
}

